CREATE TABLE helix_logs_production.releases (`published` DateTime64(3, 'UTC'), `repo` LowCardinality(String), `tag` String, `url` String, `body` String, `_version` UInt64 DEFAULT toUnixTimestamp64Milli(now64(3))) ENGINE = SharedReplacingMergeTree('/clickhouse/tables/{uuid}/{shard}', '{replica}', _version) ORDER BY (repo, tag) TTL toDateTime(published) + toIntervalWeek(2) SETTINGS index_granularity = 8192
CREATE TABLE helix_logs_production.user_shifts (`user` String, `ical_url` String) ENGINE = SharedReplacingMergeTree('/clickhouse/tables/{uuid}/{shard}', '{replica}') ORDER BY user SETTINGS index_granularity = 8192W helix_logs_production.cdn_facet_minutes_mv TO helix_logs_production.cdn_facet_minutes (`minute` DateTime, `facet` String, `dim` String, `cnt` UInt64, `cnt_ok` UInt64, `cnt_4xx` UInt64, `cnt_5xx` UInt64) AS SELECT toStartOfMinute(timestamp) AS minute, facet, dim, sum(weight) AS cnt, sumIf(weight, `response.status` < 400) AS cnt_ok, sumIf(weight, `response.status` >= 400 AND `response.status` < 500) AS cnt_4xx, sumIf(weight, `response.status` >= 500) AS cnt_5xx FROM helix_logs_production.delivery ARRAY JOIN ['datacenter', 'request_type', 'backend_type', 'content_type', 'status', 'accept', 'accept_encoding', 'cache_control', 'byo_cdn', 'x_error_grouped', 'method', 'cache_status', 'status_range', 'source', 'tier'] AS facet, [toString(`cdn.datacenter`), toString(`helix.request_type`), toString(`helix.backend_type`), toString(`response.headers.content_type`), toString(`response.status`), toString(`request.headers.accept`), toString(`request.headers.accept_encoding`), toString(`request.headers.cache_control`), toString(`request.headers.x_byo_cdn_type`), replaceRegexpAll(`response.headers.x_error`, '/[a-zA-Z0-9/_.-]+', '/...'), toString(`request.method`), upper(`cdn.cache_status`), concat(toString(intDiv(`response.status`, 100)), 'xx'), toString(source), toString(`helix.contentbus_prefix`)] AS dim GROUP BY minute, facet, dim

